223→                eq(AnnouncementEntity::getIsDeleted, false).eq(AnnouncementEntity::getType, AnnouncementType.TIMED.getCode())
224→                .orderByDesc(AnnouncementEntity::getCreatedAt));
225→        AnnouncementEntity announcement = announcementList == null || announcementList.isEmpty() ? null : announcementList.getFirst();
