246→    @Override
247→    public void syncAnnouncement() {
248→        // 轮询接口
249→        // 从外网获取还没有发布的公告
250→        List<AnnouncementEntity> exactAnnouncementList = collabspaceGrpcClientService.getExactAnnouncement();
251→        // 比较内网数据库的公告
252→        List<Long> announcementIdList = exactAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
253→        List<AnnouncementEntity> interAnnouncementList = CollectionUtil.isEmpty(announcementIdList) ? new ArrayList<>()
254→                :announcementMapper.selectBatchIds(announcementIdList);
255→        List<Long> existedAnnouncementIdList = interAnnouncementList.stream().map(AnnouncementEntity::getId).toList();
256→        List<AnnouncementEntity> updateList = interAnnouncementList.stream().filter(o ->
257→                announcementIdList.contains(o.getId())).toList();
258→        List<AnnouncementEntity> addList = exactAnnouncementList.stream().filter(o ->
259→                !existedAnnouncementIdList.contains(o.getId())).toList();
260→
261→        if (!addList.isEmpty()) {
262→            for (AnnouncementEntity addAnnouncement : addList) {
263→                announcementMapper.insert(addAnnouncement);
264→            }
265→        }
266→
267→        if (!updateList.isEmpty()) {
268→            for (AnnouncementEntity updateAnnouncement : updateList) {
269→                announcementMapper.updateById(updateAnnouncement);
270→            }
271→        }
272→
273→        // id存在，覆盖数据
274→        // id不存在，创建新的数据
275→    }
